'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';

interface ProvinceData {
  id: string;
  name: string;
  volunteers: number;
  activities: number;
  sentiment: 'high' | 'medium' | 'low';
}

const provincesData: ProvinceData[] = [
  { id: 'bangkok', name: 'กรุงเทพมหานคร', volunteers: 45, activities: 128, sentiment: 'high' },
  { id: 'chiangmai', name: 'เชียงใหม่', volunteers: 32, activities: 89, sentiment: 'high' },
  { id: 'phuket', name: 'ภูเก็ต', volunteers: 28, activities: 76, sentiment: 'high' },
  { id: 'chonburi', name: 'ชลบุรี', volunteers: 35, activities: 95, sentiment: 'high' },
  { id: 'khonkaen', name: 'ขอนแก่น', volunteers: 24, activities: 67, sentiment: 'medium' },
  { id: 'nakhonratchasima', name: 'นครราชสีมา', volunteers: 22, activities: 58, sentiment: 'medium' },
  { id: 'songkhla', name: 'สงขลา', volunteers: 19, activities: 52, sentiment: 'medium' },
  { id: 'chiangrai', name: 'เชียงราย', volunteers: 15, activities: 43, sentiment: 'medium' },
  { id: 'phitsanulok', name: 'พิษณุโลก', volunteers: 12, activities: 34, sentiment: 'low' },
  { id: 'ubon', name: 'อุบลราชธานี', volunteers: 11, activities: 31, sentiment: 'low' },
];

const getSentimentColor = (sentiment: string) => {
  switch (sentiment) {
    case 'high': return '#10B981';
    case 'medium': return '#FBBF24';
    case 'low': return '#9CA3AF';
    default: return '#9CA3AF';
  }
};

export default function ThailandMap() {
  const [hoveredProvince, setHoveredProvince] = useState<ProvinceData | null>(null);
  const [selectedProvince, setSelectedProvince] = useState<ProvinceData | null>(null);

  // Simplified Thailand map paths - in production would use proper geoJSON
  const provincePaths: Record<string, { path: string; name: string; x: number; y: number }> = {
    chiangmai: { path: 'M85,40 L95,35 L105,40 L110,50 L100,60 L90,55 Z', name: 'เชียงใหม่', x: 95, y: 48 },
    chiangrai: { path: 'M105,30 L120,25 L130,35 L125,45 L110,40 Z', name: 'เชียงราย', x: 118, y: 35 },
    phitsanulok: { path: 'M100,80 L115,75 L125,85 L120,95 L105,90 Z', name: 'พิษณุโลก', x: 112, y: 84 },
    khonkaen: { path: 'M140,90 L160,85 L170,95 L160,105 L140,100 Z', name: 'ขอนแก่น', x: 155, y: 94 },
    ubon: { path: 'M180,110 L200,105 L210,115 L200,125 L185,120 Z', name: 'อุบลฯ', x: 195, y: 114 },
    nakhonratchasima: { path: 'M150,130 L175,125 L185,135 L175,145 L155,140 Z', name: 'นครราชสีมา', x: 168, y: 134 },
    bangkok: { path: 'M115,160 L135,155 L145,165 L135,175 L120,170 Z', name: 'กทม.', x: 130, y: 164 },
    chonburi: { path: 'M145,165 L165,160 L175,170 L165,180 L150,175 Z', name: 'ชลบุรี', x: 160, y: 168 },
    songkhla: { path: 'M125,240 L145,235 L155,245 L145,255 L130,250 Z', name: 'สงขลา', x: 140, y: 244 },
    phuket: { path: 'M85,260 L105,255 L110,265 L100,270 L90,265 Z', name: 'ภูเก็ต', x: 98, y: 262 },
  };

  return (
    <div className="relative w-full h-full">
      <svg viewBox="0 0 250 300" className="w-full h-full drop-shadow-2xl">
        {/* Background gradient */}
        <defs>
          <linearGradient id="mapGradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#E0F7FA" />
            <stop offset="50%" stopColor="#E8F5E9" />
            <stop offset="100%" stopColor="#F3E5F5" />
          </linearGradient>
          <filter id="glow">
            <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
            <feMerge>
              <feMergeNode in="coloredBlur"/>
              <feMergeNode in="SourceGraphic"/>
            </feMerge>
          </filter>
        </defs>

        {/* Thailand base shape */}
        <path 
          d="M90,25 Q100,20 115,25 L130,30 Q145,35 155,45 L165,55 Q175,65 180,80 L185,95 Q190,110 195,125 L200,140 Q205,155 200,170 L195,185 Q190,200 185,215 L180,230 Q175,245 165,255 L155,265 Q145,275 130,278 L115,280 Q100,278 90,275 L80,270 Q70,265 65,255 L60,245 Q55,235 60,220 L65,205 Q70,190 75,175 L80,160 Q85,145 82,130 L78,115 Q75,100 78,85 L82,70 Q85,55 88,40 Z"
          fill="url(#mapGradient)"
          stroke="#0891B2"
          strokeWidth="2"
          opacity="0.3"
        />

        {/* Province markers */}
        {provincesData.map((province) => {
          const pathData = provincePaths[province.id];
          if (!pathData) return null;

          return (
            <g key={province.id}>
              <motion.path
                d={pathData.path}
                fill={getSentimentColor(province.sentiment)}
                stroke="white"
                strokeWidth="2"
                initial={{ scale: 1, opacity: 0.8 }}
                whileHover={{ scale: 1.2, opacity: 1 }}
                whileTap={{ scale: 0.95 }}
                onHoverStart={() => setHoveredProvince(province)}
                onHoverEnd={() => setHoveredProvince(null)}
                onClick={() => setSelectedProvince(province)}
                className="cursor-pointer"
                style={{ filter: hoveredProvince?.id === province.id ? 'url(#glow)' : 'none' }}
              />
              {/* Pulse animation for high activity */}
              {province.sentiment === 'high' && (
                <motion.circle
                  cx={pathData.x}
                  cy={pathData.y}
                  r="8"
                  fill={getSentimentColor(province.sentiment)}
                  opacity="0.3"
                  animate={{
                    scale: [1, 1.5, 1],
                    opacity: [0.3, 0.1, 0.3],
                  }}
                  transition={{
                    duration: 2,
                    repeat: Infinity,
                    ease: "easeInOut",
                  }}
                />
              )}
            </g>
          );
        })}

        {/* Connection lines from hub */}
        <motion.path
          d="M130,164 L95,48 M130,164 L118,35 M130,164 L112,84 M130,164 L155,94 M130,164 L195,114 M130,164 L168,134 M130,164 L160,168 M130,164 L140,244 M130,164 L98,262"
          stroke="#67E8F9"
          strokeWidth="1"
          strokeDasharray="5,5"
          fill="none"
          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 0.5 }}
          transition={{ duration: 2, ease: "easeInOut" }}
        />

        {/* Hub marker */}
        <motion.g
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ delay: 0.5, type: "spring" }}
        >
          <circle
            cx="130"
            cy="164"
            r="12"
            fill="#FBBF24"
            stroke="white"
            strokeWidth="3"
            filter="url(#glow)"
          />
          <text x="130" y="168" textAnchor="middle" fontSize="12">🏠</text>
        </motion.g>
      </svg>

      {/* Tooltip */}
      {hoveredProvince && (
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="absolute top-4 left-4 bg-white/95 backdrop-blur-md rounded-xl p-4 shadow-2xl border border-emerald-100 z-10"
        >
          <h4 className="font-bold text-lg text-gray-800 mb-2">{hoveredProvince.name}</h4>
          <div className="space-y-1 text-sm">
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
              <span className="text-gray-600">อาสาสมัคร:</span>
              <span className="font-semibold text-emerald-600">{hoveredProvince.volunteers} คน</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-amber-500"></span>
              <span className="text-gray-600">กิจกรรม:</span>
              <span className="font-semibold text-amber-600">{hoveredProvince.activities} ครั้ง</span>
            </div>
            <div className="flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${
                hoveredProvince.sentiment === 'high' ? 'bg-emerald-500' :
                hoveredProvince.sentiment === 'medium' ? 'bg-amber-500' : 'bg-gray-400'
              }`}></span>
              <span className="text-gray-600">ความคึกคัก:</span>
              <span className={`font-semibold ${
                hoveredProvince.sentiment === 'high' ? 'text-emerald-600' :
                hoveredProvince.sentiment === 'medium' ? 'text-amber-600' : 'text-gray-500'
              }`}>
                {hoveredProvince.sentiment === 'high' ? 'สูง' :
                 hoveredProvince.sentiment === 'medium' ? 'ปานกลาง' : 'เริ่มต้น'}
              </span>
            </div>
          </div>
        </motion.div>
      )}

      {/* Legend */}
      <div className="absolute bottom-4 right-4 bg-white/90 backdrop-blur-sm rounded-xl p-3 shadow-lg">
        <div className="text-xs font-semibold text-gray-600 mb-2">ความคึกคัก</div>
        <div className="space-y-1.5">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-emerald-500"></div>
            <span className="text-xs text-gray-600">สูง</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-amber-500"></div>
            <span className="text-xs text-gray-600">ปานกลาง</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-gray-400"></div>
            <span className="text-xs text-gray-600">เริ่มต้น</span>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { motion } from 'framer-motion';

interface FunnelStage {
  name: string;
  count: number;
  label: string;
  color: string;
  icon: string;
}

const funnelData: FunnelStage[] = [
  { name: 'Open Space', count: 12450, label: 'คนแปลกหน้า', color: 'from-violet-400 to-violet-600', icon: '👤' },
  { name: 'Study Corner', count: 5280, label: 'ผู้เริ่มเติบโต', color: 'from-cyan-400 to-cyan-600', icon: '📖' },
  { name: 'Inner Circle', count: 2156, label: 'ครอบครัวอาสา', color: 'from-amber-400 to-amber-600', icon: '🤝' },
];

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.2,
    },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 20, scale: 0.9 },
  visible: {
    opacity: 1,
    y: 0,
    scale: 1,
    transition: {
      type: 'spring',
      stiffness: 100,
    },
  },
};

export default function UserFunnel() {
  const conversionRate = ((funnelData[2].count / funnelData[0].count) * 100).toFixed(1);

  return (
    <motion.div
      variants={containerVariants}
      initial="hidden"
      animate="visible"
      className="flex flex-col gap-4"
    >
      {funnelData.map((stage, index) => (
        <motion.div
          key={stage.name}
          variants={itemVariants}
          className="relative"
        >
          <motion.div
            className={`relative bg-gradient-to-r ${stage.color} rounded-2xl p-5 shadow-xl`}
            style={{
              clipPath: index === 0 
                ? 'polygon(0 0, 100% 0, 95% 100%, 5% 100%)'
                : index === 1
                ? 'polygon(5% 0, 95% 0, 90% 100%, 10% 100%)'
                : 'polygon(10% 0, 90% 0, 85% 100%, 15% 100%)',
              marginLeft: `${index * 20}px`,
              marginRight: `${index * 20}px`,
            }}
            whileHover={{ scale: 1.02, zIndex: 10 }}
            transition={{ type: 'spring', stiffness: 300 }}
          >
            {/* Floating avatars */}
            <div className="flex justify-center -mt-2 mb-2">
              {[...Array(Math.min(3, index + 2))].map((_, i) => (
                <motion.div
                  key={i}
                  className="w-9 h-9 rounded-full bg-white/90 flex items-center justify-center text-lg shadow-md -ml-2 first:ml-0 border-2 border-white/50"
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ delay: 0.3 + i * 0.1 }}
                  whileHover={{ scale: 1.2, zIndex: 20 }}
                >
                  {stage.icon}
                </motion.div>
              ))}
              {index === 0 && (
                <motion.div
                  className="w-9 h-9 rounded-full bg-white/80 flex items-center justify-center text-sm font-bold shadow-md -ml-2 border-2 border-white/50"
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ delay: 0.6 }}
                >
                  +
                </motion.div>
              )}
            </div>

            <div className="text-center text-white">
              <motion.div
                className="text-3xl font-bold drop-shadow-lg"
                initial={{ opacity: 0, scale: 0 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ delay: 0.4 + index * 0.1, type: 'spring' }}
              >
                {stage.count.toLocaleString()}
              </motion.div>
              <div className="text-sm font-medium opacity-90 mt-1">{stage.name}</div>
              <div className="text-xs opacity-75">{stage.label}</div>
            </div>

            {/* Shine effect */}
            <motion.div
              className="absolute inset-0 rounded-2xl bg-gradient-to-r from-transparent via-white/20 to-transparent"
              animate={{
                x: ['-100%', '100%'],
              }}
              transition={{
                duration: 2,
                repeat: Infinity,
                repeatDelay: 3,
              }}
            />
          </motion.div>

          {/* Arrow between stages */}
          {index < funnelData.length - 1 && (
            <motion.div
              className="flex justify-center -my-1"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.5 + index * 0.2 }}
            >
              <motion.div
                className="text-emerald-500 text-2xl"
                animate={{ y: [0, 5, 0] }}
                transition={{ duration: 1.5, repeat: Infinity }}
              >
                ▼
              </motion.div>
            </motion.div>
          )}
        </motion.div>
      ))}

      {/* Conversion Rate */}
      <motion.div
        className="mt-4 bg-gradient-to-r from-emerald-100 to-emerald-50 rounded-2xl p-5 text-center border border-emerald-200 shadow-lg"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.8 }}
        whileHover={{ scale: 1.02 }}
      >
        <motion.div
          className="text-4xl font-bold text-emerald-600"
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ delay: 1, type: 'spring', stiffness: 200 }}
        >
          {conversionRate}%
        </motion.div>
        <div className="text-sm text-emerald-700 mt-1 font-medium">Conversion Rate</div>
        <div className="text-xs text-emerald-600/70">จากแปลกหน้า → ครอบครัว</div>
      </motion.div>
    </motion.div>
  );
}

'use client';

import { motion } from 'framer-motion';
import { TrendingUp, Coins, Ticket, Gem } from 'lucide-react';

interface KPICardProps {
  icon: React.ReactNode;
  value: string;
  label: string;
  growth: string;
  color: string;
  delay: number;
}

function KPICard({ icon, value, label, growth, color, delay }: KPICardProps) {
  return (
    <motion.div
      className={`relative overflow-hidden rounded-2xl p-5 border-2 ${color} bg-gradient-to-br from-amber-50 to-yellow-50 shadow-lg`}
      initial={{ opacity: 0, y: 20, scale: 0.9 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      transition={{ delay, type: 'spring', stiffness: 100 }}
      whileHover={{ scale: 1.03, y: -5 }}
    >
      {/* Glow effect */}
      <div className={`absolute -top-10 -right-10 w-32 h-32 rounded-full ${color.replace('border-', 'bg-').replace('500', '200')} opacity-50 blur-2xl`} />

      <div className="relative z-10">
        <motion.div
          className="text-4xl mb-3"
          initial={{ rotate: -10, scale: 0 }}
          animate={{ rotate: 0, scale: 1 }}
          transition={{ delay: delay + 0.2, type: 'spring' }}
        >
          {icon}
        </motion.div>

        <motion.div
          className="text-2xl font-bold text-amber-800"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: delay + 0.3 }}
        >
          {value}
        </motion.div>

        <div className="text-sm text-amber-700/80 mt-1">{label}</div>

        <motion.div
          className="inline-flex items-center gap-1 mt-3 bg-emerald-500 text-white text-xs font-bold px-3 py-1.5 rounded-full"
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ delay: delay + 0.4, type: 'spring' }}
        >
          <TrendingUp className="w-3 h-3" />
          {growth}
        </motion.div>
      </div>
    </motion.div>
  );
}

export default function EconomicHealth() {
  return (
    <div className="space-y-5">
      {/* KPI Grid */}
      <div className="grid grid-cols-2 gap-4">
        <KPICard
          icon="🪙"
          value="2.45M"
          label="เหรียญหมุนเวียนในระบบ"
          growth="+23%"
          color="border-amber-400"
          delay={0}
        />
        <KPICard
          icon="🎫"
          value="856K"
          label="Token ที่ใช้งานอยู่"
          growth="+18%"
          color="border-amber-400"
          delay={0.1}
        />
      </div>

      {/* Blessing Pool */}
      <motion.div
        className="relative overflow-hidden rounded-2xl p-6 bg-gradient-to-br from-sky-100 to-blue-50 border-2 border-sky-300 shadow-xl"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2, type: 'spring' }}
        whileHover={{ scale: 1.02 }}
      >
        {/* Animated background */}
        <motion.div
          className="absolute inset-0 bg-gradient-to-r from-sky-200/0 via-sky-200/30 to-sky-200/0"
          animate={{
            x: ['-100%', '100%'],
          }}
          transition={{
            duration: 3,
            repeat: Infinity,
            repeatDelay: 2,
          }}
        />

        {/* Diamond decoration */}
        <motion.div
          className="absolute -top-6 -right-6 text-8xl opacity-20"
          animate={{ rotate: 360 }}
          transition={{ duration: 20, repeat: Infinity, ease: 'linear' }}
        >
          💎
        </motion.div>

        <div className="relative z-10 text-center">
          <motion.div
            className="text-5xl mb-2"
            initial={{ scale: 0, rotate: -180 }}
            animate={{ scale: 1, rotate: 0 }}
            transition={{ delay: 0.3, type: 'spring', stiffness: 200 }}
          >
            💎
          </motion.div>

          <motion.div
            className="text-4xl font-bold text-sky-700"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
          >
            ฿ 1,250,000
          </motion.div>

          <div className="text-sky-800 font-medium mt-2">The Blessing Pool</div>
          <div className="text-sm text-sky-600/80">ยอดสนับสนุนจาก Sponsors</div>

          <motion.div
            className="inline-flex items-center gap-1 mt-4 bg-emerald-500 text-white text-sm font-bold px-4 py-2 rounded-full shadow-lg"
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ delay: 0.5, type: 'spring' }}
          >
            <TrendingUp className="w-4 h-4" />
            +45% จากเดือนที่แล้ว
          </motion.div>
        </div>
      </motion.div>
    </div>
  );
}

'use client';

import { motion } from 'framer-motion';
import { AreaChart, Area, XAxis, YAxis, ResponsiveContainer, Tooltip } from 'recharts';

const moodData = [
  { day: 'จ', mood: 45 },
  { day: 'อ', mood: 52 },
  { day: 'พ', mood: 48 },
  { day: 'พฤ', mood: 65 },
  { day: 'ศ', mood: 72 },
  { day: 'ส', mood: 78 },
  { day: 'อา', mood: 82 },
];

const sparklineData = [30, 45, 25, 60, 40, 35, 50];

export default function SafetySentiment() {
  return (
    <div className="grid grid-cols-2 gap-4">
      {/* SOS Cases */}
      <motion.div
        className="bg-gradient-to-br from-rose-100 to-red-50 rounded-2xl p-5 border-2 border-rose-300 shadow-lg"
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ delay: 0.1 }}
        whileHover={{ scale: 1.02 }}
      >
        <div className="text-center">
          <div className="text-rose-800 font-bold text-sm mb-3">SOS Cases Detected</div>

          {/* Gauge */}
          <div className="relative w-24 h-12 mx-auto mb-3">
            <svg viewBox="0 0 100 50" className="w-full h-full">
              <path
                d="M 10 50 A 40 40 0 0 1 90 50"
                fill="none"
                stroke="rgba(255,255,255,0.5)"
                strokeWidth="10"
              />
              <motion.path
                d="M 10 50 A 40 40 0 0 1 50 10"
                fill="none"
                stroke="#EF4444"
                strokeWidth="10"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 0.3 }}
                transition={{ delay: 0.5, duration: 1 }}
              />
            </svg>
            <motion.div
              className="absolute bottom-0 left-1/2 -translate-x-1/2 text-2xl font-bold text-rose-600"
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ delay: 0.7, type: 'spring' }}
            >
              12
            </motion.div>
          </div>

          {/* Sparkline */}
          <div className="flex items-end justify-center gap-1 h-10 mb-3">
            {sparklineData.map((value, i) => (
              <motion.div
                key={i}
                className="w-3 bg-gradient-to-t from-rose-400 to-rose-300 rounded-t"
                style={{ height: `${value}%` }}
                initial={{ scaleY: 0 }}
                animate={{ scaleY: 1 }}
                transition={{ delay: 0.3 + i * 0.05 }}
              />
            ))}
          </div>

          <motion.div
            className="inline-flex items-center gap-2 bg-white text-emerald-600 font-bold px-4 py-2 rounded-full shadow-md"
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ delay: 0.8, type: 'spring' }}
          >
            <span className="text-emerald-500">✓</span>
            92% Success Rate
          </motion.div>
        </div>
      </motion.div>

      {/* Mood Monitoring */}
      <motion.div
        className="bg-gradient-to-br from-emerald-100 to-green-50 rounded-2xl p-5 border-2 border-emerald-300 shadow-lg"
        initial={{ opacity: 0, x: 20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ delay: 0.2 }}
        whileHover={{ scale: 1.02 }}
      >
        <div className="text-emerald-800 font-bold text-sm mb-3 text-center">Overall Mood</div>

        {/* Mood Chart */}
        <div className="h-24 mb-2">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={moodData}>
              <defs>
                <linearGradient id="moodGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#34D399" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#34D399" stopOpacity={0.1}/>
                </linearGradient>
              </defs>
              <Area
                type="monotone"
                dataKey="mood"
                stroke="#10B981"
                strokeWidth={2}
                fill="url(#moodGradient)"
                animationDuration={1500}
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        {/* Mood Emojis */}
        <div className="flex justify-between text-lg mb-3 px-2">
          {['😔', '😐', '🙂', '😊', '🥰'].map((emoji, i) => (
            <motion.span
              key={i}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.4 + i * 0.1 }}
            >
              {emoji}
            </motion.span>
          ))}
        </div>

        <motion.div
          className="bg-white rounded-xl p-3 text-center shadow-md"
          initial={{ scale: 0.9 }}
          animate={{ scale: 1 }}
          transition={{ delay: 0.6 }}
        >
          <motion.span
            className="text-2xl font-bold text-emerald-600"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            +72%
          </motion.span>
          <div className="text-xs text-emerald-700">Positive Sentiment</div>
        </motion.div>
      </motion.div>
    </div>
  );
}

