// Check what's inside aunjai-knowledge index
import { Pinecone } from '@pinecone-database/pinecone';
import * as dotenv from 'dotenv';

dotenv.config();

async function checkKnowledgeBase() {
  const pc = new Pinecone({
    apiKey: process.env.PINECONE_API_KEY || '',
  });

  const indexName = 'aunjai-knowledge';
  const index = pc.index(indexName);

  console.log(`🔍 Checking index: ${indexName}\n`);

  // Get index stats
  const stats = await index.describeIndexStats();
  console.log('📊 Index Stats:');
  console.log(`  - Dimension: ${stats.dimension}`);
  console.log(`  - Total Records: ${stats.totalRecordCount}`);
  console.log(`  - Namespaces: ${Object.keys(stats.namespaces || {}).join(', ') || 'default'}`);

  // Query with a dummy vector to get some records
  // Using 384 dimensions (from the stats we saw earlier)
  console.log('\n📚 Sample Records:');
  const dummyVector = new Array(384).fill(0).map(() => Math.random() - 0.5);

  try {
    const results = await index.query({
      vector: dummyVector,
      topK: 10,
      includeMetadata: true,
    });

    if (results.matches && results.matches.length > 0) {
      results.matches.forEach((match, i) => {
        console.log(`\n[${i + 1}] ID: ${match.id}`);
        console.log(`    Score: ${match.score?.toFixed(4)}`);
        console.log(`    Metadata:`, JSON.stringify(match.metadata, null, 2));
      });
    } else {
      console.log('  (No records found with random query)');
    }

    // Try to query with zero vector to get any records
    console.log('\n📖 Trying to fetch all records...');
    const zeroVector = new Array(384).fill(0);
    const allResults = await index.query({
      vector: zeroVector,
      topK: 100,
      includeMetadata: true,
    });

    if (allResults.matches && allResults.matches.length > 0) {
      console.log(`Found ${allResults.matches.length} records:\n`);
      allResults.matches.forEach((match, i) => {
        const text = match.metadata?.text || match.metadata?.content || JSON.stringify(match.metadata);
        console.log(`${i + 1}. [${match.id}] ${text?.substring(0, 100)}...`);
      });
    }

  } catch (error) {
    console.error('❌ Error querying:', error.message);
  }
}

checkKnowledgeBase().catch(console.error);

// Use Hugging Face for embeddings (FREE - no API key needed!)
import { Pinecone } from '@pinecone-database/pinecone';
import * as dotenv from 'dotenv';

dotenv.config();

const HF_API_URL = 'https://api-inference.huggingface.co/pipeline/feature-extraction/sentence-transformers/all-MiniLM-L6-v2';

// Generate embeddings using Hugging Face (384 dimensions for aunjai-knowledge)
async function generateEmbedding(text: string): Promise<number[]> {
  const response = await fetch(HF_API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ inputs: text }),
  });

  if (!response.ok) {
    throw new Error(`HF API error: ${response.status}`);
  }

  const embedding = await response.json();
  return embedding[0]; // Returns 384-dim vector
}

// Save to Pinecone
async function saveToKnowledgeBase(id: string, text: string, metadata: any) {
  const pc = new Pinecone({ apiKey: process.env.PINECONE_API_KEY! });
  const index = pc.index('aunjai-knowledge');

  console.log(`🔄 Generating embedding for: ${id}`);
  const embedding = await generateEmbedding(text);

  await index.upsert([{
    id,
    values: embedding,
    metadata: {
      text: text.substring(0, 1000), // Limit text size
      ...metadata,
      timestamp: new Date().toISOString(),
    }
  }]);

  console.log(`✅ Saved: ${id}`);
}

// Import from memory files
async function importMemoryFiles() {
  const files = [
    { path: 'SOUL.md', category: 'vision' },
    { path: 'IDENTITY.md', category: 'identity' },
    { path: 'AGENTS.md', category: 'agents' },
    { path: 'USER.md', category: 'user' },
    { path: 'TOOLS.md', category: 'tools' },
    { path: 'BOOTSTRAP.md', category: 'bootstrap' },
    { path: 'HEARTBEAT.md', category: 'safety' },
    { path: 'MEMORY.md', category: 'memory' },
  ];

  for (const file of files) {
    try {
      const content = await Bun.file(`./${file.path}`).text();

      // Split into chunks (max 500 chars each)
      const chunks = content.match(/[\s\S]{1,500}/g) || [content];

      for (let i = 0; i < chunks.length; i++) {
        const chunkId = `${file.path.replace('.md', '')}-chunk-${i}`;
        await saveToKnowledgeBase(chunkId, chunks[i], {
          source: file.path,
          category: file.category,
          chunkIndex: i,
        });

        // Rate limiting - wait 1 second between requests
        await new Promise(r => setTimeout(r, 1000));
      }

    } catch (error) {
      console.error(`❌ Error importing ${file.path}:`, error.message);
    }
  }

  console.log('\n🎉 Import complete!');
}

// Run import
// importMemoryFiles();

export { generateEmbedding, saveToKnowledgeBase, importMemoryFiles };

#!/usr/bin/env node
/**
 * Simple embedding using local onnx runtime
 * No API key needed!
 */

import { Pinecone } from '@pinecone-database/pinecone';
import { readFileSync } from 'fs';
import * as dotenv from 'dotenv';

dotenv.config();

// Simple hash-based embedding (fallback when no API available)
// ทำงานได้แต่ไม่แม่นยำเท่า AI embeddings
function simpleEmbedding(text: string, dim: number = 384): number[] {
  const vector = new Array(dim).fill(0);

  for (let i = 0; i < text.length; i++) {
    const char = text.charCodeAt(i);
    vector[i % dim] += char / 1000;
  }

  // Normalize
  const magnitude = Math.sqrt(vector.reduce((sum, v) => sum + v * v, 0));
  return vector.map(v => v / (magnitude || 1));
