const { Pinecone } = require('@pinecone-database/pinecone');
const { readFileSync } = require('fs');
require('dotenv').config();

// Simple hash-based embedding (384 dimensions)
function simpleEmbedding(text, dim = 384) {
  const vector = new Array(dim).fill(0);

  for (let i = 0; i < text.length; i++) {
    const char = text.charCodeAt(i);
    vector[i % dim] += char / 1000;
  }

  // Normalize
  const magnitude = Math.sqrt(vector.reduce((sum, v) => sum + v * v, 0));
  return vector.map(v => v / (magnitude || 1));
}

// Split text into chunks by size
function chunkText(text, maxSize = 800) {
  const chunks = [];
  let start = 0;

  while (start < text.length) {
    let end = start + maxSize;
    if (end >= text.length) {
      chunks.push(text.slice(start));
      break;
    }
    // Find nearest line break
    const nextBreak = text.lastIndexOf('\n', end);
    if (nextBreak > start) {
      end = nextBreak;
    }
    chunks.push(text.slice(start, end).trim());
    start = end + 1;
  }

  return chunks.filter(c => c.length > 50);
}

// Import files to Pinecone
async function importFiles() {
  const pc = new Pinecone({ apiKey: process.env.PINECONE_API_KEY });
