/**
 * OpenClaw Memory (Pinecone) Plugin
 * 
 * Auto-save conversations to Pinecone vector database
 * for long-term memory and semantic search
 */

import type { OpenClawPluginApi } from "openclaw/plugin-sdk";

// Configuration
const PINECONE_API_KEY = process.env.PINECONE_API_KEY || '';
const INDEX_NAME = process.env.PINECONE_INDEX || 'aunjai-knowledge';
const DIMENSION = 384;

let indexHost: string | null = null;

// Simple embedding (same as our working implementation)
function embed(text: string): number[] {
  const vec = new Array(DIMENSION).fill(0);
  for (let i = 0; i < text.length; i++) {
    vec[i % DIMENSION] += (text.charCodeAt(i) % 100) / 100;
  }
  const mag = Math.sqrt(vec.reduce((s, v) => s + v * v, 0));
  return vec.map(v => v / (mag || 1));
}

// Get Pinecone index host
async function getIndexHost(): Promise<string> {
  if (indexHost) return indexHost;

  const resp = await fetch('https://api.pinecone.io/indexes', {
    headers: { 'Api-Key': PINECONE_API_KEY }
  });
  const data = await resp.json();
  const index = data.indexes.find((i: any) => i.name === INDEX_NAME);
  if (!index) throw new Error(`Index ${INDEX_NAME} not found`);

  indexHost = index.host;
  return indexHost;
}

// Save vector to Pinecone
async function saveToPinecone(id: string, text: string, metadata: Record<string, any>) {
  try {
    const host = await getIndexHost();

    await fetch(`https://${host}/vectors/upsert`, {
      method: 'POST',
      headers: {
        'Api-Key': PINECONE_API_KEY,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        vectors: [{
          id: `${id}-${Date.now()}`,
          values: embed(text),
          metadata: {
            text: text.substring(0, 1500),
            ...metadata,
            savedAt: new Date().toISOString()
          }
        }],
        namespace: ''
      })
    });

    console.log(`[Pinecone] Saved: ${id}`);
  } catch (err) {
    console.error('[Pinecone] Save failed:', err);
  }
}

// Export plugin
export function activate(api: OpenClawPluginApi) {
  console.log('[Pinecone Memory] Plugin activated');

  // Hook: When message is received from user
  api.hooks.register('message_received', async (event) => {
    await saveToPinecone(
      `msg-in-${Date.now()}`,
      `${event.from}: ${event.content}`,
      {
        type: 'incoming',
        from: event.from,
        timestamp: event.timestamp || Date.now(),
        ...event.metadata
      }
    );
  });

  // Hook: When message is sent to user
  api.hooks.register('message_sent', async (event) => {
    if (event.success) {
      await saveToPinecone(
        `msg-out-${Date.now()}`,
        `assistant: ${event.content}`,
        {
          type: 'outgoing',
          to: event.to,
          success: event.success,
          ...event.metadata
        }
      );
    }
  });

  // Hook: When session ends - save summary
  api.hooks.register('session_end', async (event) => {
    await saveToPinecone(
      `session-${event.sessionKey || Date.now()}`,
      `Session ended. Duration: ${event.duration || 'unknown'}`,
      {
        type: 'session',
        sessionKey: event.sessionKey,
        duration: event.duration,
        timestamp: Date.now()
      }
    );
  });

  console.log('[Pinecone Memory] Hooks registered');
}

